// Patrón creacional que se utiliza para crear nuevos objetos a partir de una copia (o clon) de un objeto existente
package main

import "fmt"

type prototype struct {
	name    string
	age     int
	friends []string
	color   *string
	phones  map[string]string
}


// IMPORTANT
func (p *prototype) Clone() prototype {
	friends := make([]string, len(p.friends), len(p.friends))
	copy(friends, p.friends)

	color := *p.color

	phones := map[string]string{}

	for k, v := range p.phones {
		phones[k] = v
	}

	return prototype{
		name:    p.name,
		age:     p.age,
		friends: friends,
		color:   &color,
		phones:  phones,
	}

}

func main() {
	color := "yellow"
	p1 := prototype{
		name:    "Marce",
		age:     43,
		friends: []string{"Natish", "Allisson", "Roger"},
		color:   &color,
		phones:  map[string]string{"choco": "1234", "payo": "4321"},
	}

	p2 := p1.Clone()
	p2.name = "Natish"
	p2.age = 6
	p2.friends[0] = "Marce"
	p2.phones["choco"] = "567"
	color = "blue"
}

