func (t *Task) String() string {
	sb := strings.Builder{}
	sb.WriteString("\t|--")
	sb.WriteString(t.Name)
	sb.WriteString(" - ")
	sb.WriteString(t.Responsable)
	sb.WriteString(" $")
	sb.WriteString(strconv.Itoa(t.Price()))
	sb.WriteString("\n")

	for _, subTask := range t.SubTask {
		sb.WriteString(subTask.String())
	}

	return sb.String()
}

func (t *Task) Price() int {
	price := t.TaskPrice

	for _, subTask := range t.SubTask {
		price += subTask.Price()
	}

	return price
}

